#!/usr/bin/env dotnet
// Find the earliest Friday the 13th in the proleptic Gregorian calendar (starting 0001-01-01)
// and count total Friday the 13ths in a full 400-year cycle.

// Find the earliest Friday the 13th
DateOnly earliest = default;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
        {
            if (earliest == default)
            {
                earliest = d;
                Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd}");
            }
        }
    }
}

// Count all Friday the 13ths in a 400-year cycle (years 1–400)
int count = 0;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
            count++;
    }
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// Bonus: which day-of-week lands on the 13th most often?
var dayCounts = new int[7];
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        dayCounts[(int)d.DayOfWeek]++;
    }
}

Console.WriteLine("\n13th falls on each day (400-year cycle):");
foreach (DayOfWeek dow in Enum.GetValues<DayOfWeek>())
    Console.WriteLine($"  {dow,-10} {dayCounts[(int)dow]}");
EOF
